import { registerMvuSchema } from 'https://testingcf.jsdelivr.net/gh/StageDog/tavern_resource/dist/util/mvu_zod.js';

const defaultProtagonist = {
  姓名: null,
  性别: null,
  年龄: null,
  性格: null,
  外观: null,
  身份: null,
  性癖: null,
  能力: null,
  背景: null
};

const defaultEnvironment = {
  当前日期: '未知',
  当前时间: '未知',
  地点: '未知',
  天气: '未知'
};

const defaultMainGoal = {
  标题: '待发布',
  描述: '暂无',
  条件: '暂无',
  完成: false
};

const defaultOngoingGoal = {
  标题: '待发布',
  描述: '暂无',
  条件: '暂无',
  完成次数: 0,
  启用: false
};

const defaultMinorNpc = {
  _类型: '次要',
  基础: {
    名称: null,
    性别: null,
    年龄: null,
    身份: null,
    与主角关系: null,
    背景简介: null
  }
};

const defaultMajorNpc = {
  _类型: '主要',
  基础: {
    名称: null,
    性别: null,
    年龄: null,
    身高: null,
    体重: null,
    身份: null,
    经济情况: null,
    居住地: null,
    与主角关系: null,
    背景经历: null
  },
  外貌: {
    面部: null,
    头发: null,
    妆容: null,
    皮肤: null,
    特征: null
  },
  体型: {
    整体体型: null,
    胸部: null,
    腰部: null,
    手部: null,
    臀部: null,
    腿部: null,
    足部: null
  },
  性格: {
    核心特质: null,
    正面特质: null,
    负面特质: null,
    行为习惯: null,
    情绪反应: null,
    社交态度: null
  },
  状态: {
    好感度: 0,
    厌恶度: 0,
    堕落度: 0
  },
  穿着: {
    上衣: null,
    下装: null,
    足部: null,
    内衣: null,
    内裤: null
  },
  贞操: {
    处女: null,
    口腔处女: null,
    肛门处女: null,
    阴茎处男: null
  },
  即时: {
    小穴: null,
    子宫: null,
    屁穴: null,
    体液: null,
    阴茎: null,
    前列腺: null,
    尿道: null,
    精液: null
  }
};

const majorNpcSchema = z.object({
  _类型: z.literal('主要'),
  基础: z.object({
    名称: z.string().nullable(),
    性别: z.enum(['男', '女']).nullable(),
    年龄: z.coerce.number().nullable(),
    身高: z.string().nullable(),
    体重: z.string().nullable(),
    身份: z.string().nullable(),
    经济情况: z.string().nullable(),
    居住地: z.string().nullable(),
    与主角关系: z.string().nullable(),
    背景经历: z.string().nullable()
  }),
  外貌: z.object({ 面部: z.string().nullable(), 头发: z.string().nullable(), 妆容: z.string().nullable(), 皮肤: z.string().nullable(), 特征: z.string().nullable() }).catch({ 面部: null, 头发: null, 妆容: null, 皮肤: null, 特征: null }),
  体型: z.object({ 整体体型: z.string().nullable(), 胸部: z.string().nullable(), 腰部: z.string().nullable(), 手部: z.string().nullable(), 臀部: z.string().nullable(), 腿部: z.string().nullable(), 足部: z.string().nullable() }).catch({ 整体体型: null, 胸部: null, 腰部: null, 手部: null, 臀部: null, 腿部: null, 足部: null }),
  性格: z.object({ 核心特质: z.string().nullable(), 正面特质: z.string().nullable(), 负面特质: z.string().nullable(), 行为习惯: z.string().nullable(), 情绪反应: z.string().nullable(), 社交态度: z.string().nullable() }).catch({ 核心特质: null, 正面特质: null, 负面特质: null, 行为习惯: null, 情绪反应: null, 社交态度: null }),
  状态: z.object({ 好感度: z.coerce.number().catch(0), 厌恶度: z.coerce.number().catch(0), 堕落度: z.coerce.number().catch(0) }).catch({ 好感度: 0, 厌恶度: 0, 堕落度: 0 }),
  穿着: z.object({ 上衣: z.string().nullable(), 下装: z.string().nullable(), 足部: z.string().nullable(), 内衣: z.string().nullable(), 内裤: z.string().nullable() }).catch({ 上衣: null, 下装: null, 足部: null, 内衣: null, 内裤: null }),
  贞操: z.object({ 处女: z.boolean().nullable(), 口腔处女: z.boolean().nullable(), 肛门处女: z.boolean().nullable(), 阴茎处男: z.boolean().nullable() }).catch({ 处女: null, 口腔处女: null, 肛门处女: null, 阴茎处男: null }),
  即时: z.object({ 小穴: z.string().nullable(), 子宫: z.string().nullable(), 屁穴: z.string().nullable(), 体液: z.string().nullable(), 阴茎: z.string().nullable(), 前列腺: z.string().nullable(), 尿道: z.string().nullable(), 精液: z.string().nullable() }).catch({ 小穴: null, 子宫: null, 屁穴: null, 体液: null, 阴茎: null, 前列腺: null, 尿道: null, 精液: null })
}).catch(defaultMajorNpc);

const minorNpcSchema = z.object({
  _类型: z.literal('次要'),
  基础: z.object({
    名称: z.string().nullable(),
    性别: z.enum(['男', '女']).nullable(),
    年龄: z.coerce.number().nullable(),
    身份: z.string().nullable(),
    与主角关系: z.string().nullable(),
    背景简介: z.string().nullable()
  })
}).catch(defaultMinorNpc);

const npcSchema = z.union([majorNpcSchema, minorNpcSchema]).catch(defaultMinorNpc);

export const Schema = z.object({
  主角: z.object({
    姓名: z.string().nullable(),
    性别: z.enum(['男', '女']).nullable(),
    年龄: z.coerce.number().nullable(),
    性格: z.string().nullable(),
    外观: z.string().nullable(),
    身份: z.string().nullable(),
    性癖: z.string().nullable(),
    能力: z.string().nullable(),
    背景: z.string().nullable()
  }).catch(defaultProtagonist),

  环境: z.object({
    当前日期: z.string().catch('未知'),
    当前时间: z.string().catch('未知'),
    地点: z.string().catch('未知'),
    天气: z.string().catch('未知')
  }).catch(defaultEnvironment),

  目标: z.object({
    主线: z.object({ 标题: z.string(), 描述: z.string(), 条件: z.string(), 完成: z.boolean() }).catch(defaultMainGoal),
    支线: z.record(z.string().describe('支线编号'), z.object({ 标题: z.string(), 描述: z.string(), 条件: z.string(), 完成: z.boolean() })).catch({}),
    持续: z.object({ 标题: z.string(), 描述: z.string(), 条件: z.string(), 完成次数: z.coerce.number().catch(0), 启用: z.boolean().catch(false) }).catch(defaultOngoingGoal)
  }).catch({ 主线: defaultMainGoal, 支线: {}, 持续: defaultOngoingGoal }),

  NPC: z.object({
    NPC1: npcSchema.optional(),
    NPC2: npcSchema.optional(),
    NPC3: npcSchema.optional(),
    NPC4: npcSchema.optional(),
    NPC5: npcSchema.optional(),
    NPC6: npcSchema.optional(),
    NPC7: npcSchema.optional(),
    NPC8: npcSchema.optional(),
    NPC9: npcSchema.optional(),
    NPC10: npcSchema.optional()
  }).nullable().optional(),

  角色关系: z.array(z.string()).catch([])
});

$(() => {
  registerMvuSchema(Schema);
});
